import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleCardAction = (type) => {
    if (type === 'payments') {
      alert("Redirecting to our Secure Payment Policy...");
    } else if (type === 'students') {
      navigate('/services'); 
    } else if (type === 'delivery') {
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden', backgroundColor: '#ffffff' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '50vh',
          padding: '60px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-4 fw-bold mb-3">Freelance <span style={{ color: '#ffc107' }}>Hub Nashik</span></h1>
          <p className="lead fs-5 mb-4 opacity-75 mx-auto" style={{ maxWidth: '700px' }}>
            Nashik's premier marketplace for student talent and professional solutions.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning px-4 py-2 fw-bold rounded-pill shadow">Hire Me</Link>
            <Link to="/register" className="btn btn-outline-light px-4 py-2 rounded-pill border-2">Join Us</Link> 
          </div>
        </div>
      </header>

      {/* 2. Top Freelancer in the CORNER (WhatsApp Chat Style) */}
      <section className="py-5">
        <div className="container">
          <div className="row">
            <div className="col-md-4">
              <h6 className="text-muted small fw-bold mb-3 text-uppercase" style={{ letterSpacing: '1px' }}>Top Freelancer</h6>
              
              {/* This is the Corner Profile Widget */}
              <div 
                onClick={() => navigate('/profile/1')}
                className="d-flex align-items-center p-2 rounded-4 shadow-sm border border-light"
                style={{ cursor: 'pointer', maxWidth: '320px', backgroundColor: '#fff', transition: '0.3s' }}
              >
                {/* Round Profile Picture in the corner */}
                <div className="position-relative">
                  <img 
                    src="https://freepik.com" 
                    className="rounded-circle border border-2 border-white shadow-sm" 
                    style={{ width: '55px', height: '55px', objectFit: 'cover' }} 
                    alt="DP" 
                  />
                  {/* WhatsApp-style Online Green Dot */}
                  <span className="position-absolute bottom-0 end-0 bg-success border border-2 border-white rounded-circle" 
                        style={{ width: '13px', height: '13px' }}></span>
                </div>

                {/* Freelancer Name and Role next to image */}
                <div className="ms-3">
                  <h6 className="mb-0 fw-bold text-dark">Rahul Patil</h6>
                  <p className="mb-0 text-muted small">React Developer • Nashik</p>
                </div>

                {/* Small arrow icon */}
                <div className="ms-auto pe-2 text-muted">
                  <small>→</small>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Features Section */}
      <section className="py-5 bg-light border-top">
        <div className="container py-4 text-center">
          <div className="row g-4">
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-6 mb-3 text-warning">🛡️</div>
                <h6 className="fw-bold">Secure Payments</h6>
                <p className="text-muted x-small">Safe transactions for every project.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-6 mb-3 text-primary">🎓</div>
                <h6 className="fw-bold">Verified Talent</h6>
                <p className="text-muted x-small">Top-rated student professionals.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-6 mb-3 text-success">⚡</div>
                <h6 className="fw-bold">Fast Delivery</h6>
                <p className="text-muted x-small">Delivery on your timeline.</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. Nashik Location Section with Fixed Map */}
      <section id="contact" className="py-5 bg-white">
        <div className="container text-center">
          <h5 className="fw-bold mb-4">📍 Our Hub in <span className="text-primary">Nashik</span></h5>
          <div className="shadow rounded-5 overflow-hidden mx-auto border border-white border-4" style={{ maxWidth: '900px', height: '350px' }}>
            <iframe
              title="Nashik Map"
              src="https://google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .feature-box:hover {
          background: #fdfdfd;
          transform: translateY(-5px);
          transition: 0.3s;
        }
      `}</style>

    </div>
  );
}

export default Home;
